var val = Services.getValue(ApplicableCostAmt.dataBinding);
var err = validateCurrencyValue(val, 999999.99);
if( null == err )
{	Services.setValue(ApplicableCostAmt.dataBinding, WPU.formatToTwoDP(val));			
}
return err;

